local h = ""
local k = 137
local out = {}
for i = 1, #h, 2 do
    local n = tonumber(h:sub(i, i + 1), 16)
    out[#out + 1] = string.char((n - k) % 256)
end
local src = table.concat(out)
local loader = loadstring or load
if not loader then
    error("loadstring unavailable")
end
local fn, err = loader(src)
if not fn then
    error(err)
end
return fn()
